"""Generate helper Go files (register.go, auth.go, request.go, polling.go, prompt.go)."""

from naming import snake_to_camel

GO_PACKAGE = "generated"


def _gen_file_header():
    """Emit the standard generated file header."""
    return ["// Code generated by generate_commands.py. DO NOT EDIT.", f"package {GO_PACKAGE}", ""]


def _gen_imports(imports):
    """Emit a Go import block. imports is a list of (group, [import_paths])."""
    lines = ["import ("]
    for i, (_, paths) in enumerate(imports):
        lines.extend(f'\t"{p}"' for p in paths)
        if i < len(imports) - 1:
            lines.append("")
    lines.append(")")
    lines.append("")
    return lines


def _gen_all_imports():
    """Emit the full import block used by generated helper files. goimports cleans unused ones."""
    return _gen_imports([
        ("stdlib", ["bufio", "context", "encoding/json", "fmt", "io", "net/http", "net/url", "os", "strings", "time"]),
        ("third", [
            "github.com/mattn/go-isatty",
            "github.com/schollz/progressbar/v3",
            "github.com/spf13/cobra",
            "github.com/spf13/viper",
        ]),
        ("internal", [
            "github.com/supermetrics-public/supermetrics-cli/internal/auth",
            "github.com/supermetrics-public/supermetrics-cli/internal/buildcfg",
            "github.com/supermetrics-public/supermetrics-cli/internal/config",
            "github.com/supermetrics-public/supermetrics-cli/internal/httpclient",
            "github.com/supermetrics-public/supermetrics-cli/internal/output",
        ]),
    ])


def _gen_spinner_block(indent):
    """Emit the spinner setup/teardown block used by executeRequest and executeAsyncQueryWithMeta."""
    t = "\t" * indent
    lines = []
    lines.append(f"{t}if isTerminal(os.Stderr) && !quiet && !verbose {{")
    lines.append(f"{t}\tbar := progressbar.NewOptions(-1,")
    lines.append(f"{t}\t\tprogressbar.OptionSetWriter(os.Stderr),")
    lines.append(f'{t}\t\tprogressbar.OptionSetDescription("[cyan]" + spinnerText + "[reset]"),')
    lines.append(f'{t}\t\tprogressbar.OptionSpinnerCustom([]string{{"⭐", "🌟"}}),')
    lines.append(f"{t}\t\tprogressbar.OptionSetSpinnerChangeInterval(200*time.Millisecond),")
    lines.append(f"{t}\t\tprogressbar.OptionThrottle(50*time.Millisecond),")
    lines.append(f"{t}\t\tprogressbar.OptionShowElapsedTimeOnFinish(),")
    lines.append(f"{t}\t\tprogressbar.OptionEnableColorCodes(true),")
    lines.append(f"{t}\t\tprogressbar.OptionClearOnFinish(),")
    lines.append(f"{t}\t)")
    lines.append(f"{t}\tstop := make(chan struct{{}})")
    lines.append(f"{t}\tgo func() {{")
    lines.append(f"{t}\t\tticker := time.NewTicker(50 * time.Millisecond)")
    lines.append(f"{t}\t\tdefer ticker.Stop()")
    lines.append(f"{t}\t\tfor {{")
    lines.append(f"{t}\t\t\tselect {{")
    lines.append(f"{t}\t\t\tcase <-stop:")
    lines.append(f"{t}\t\t\t\treturn")
    lines.append(f"{t}\t\t\tcase <-ticker.C:")
    lines.append(f"{t}\t\t\t\t_ = bar.Add(1)")
    lines.append(f"{t}\t\t\t}}")
    lines.append(f"{t}\t\t}}")
    lines.append(f"{t}\t}}()")
    lines.append(f"{t}\tdefer func() {{")
    lines.append(f"{t}\t\tclose(stop)")
    lines.append(f"{t}\t\t_ = bar.Finish()")
    lines.append(f"{t}\t}}()")
    lines.append(f"{t}}}")
    lines.append("")
    return lines


def _gen_register_go(resources):
    """Generate register.go — RegisterAll + injectable vars."""
    lines = _gen_file_header()
    lines.extend(_gen_imports([
        ("stdlib", ["net/http", "time"]),
        ("third", ["github.com/spf13/cobra"]),
    ]))
    lines.append("// httpClient is the HTTP client used by executeRequest. Nil means http.DefaultClient.")
    lines.append("// Tests can set this to inject a test-specific client.")
    lines.append("var httpClient *http.Client")
    lines.append("")
    lines.append("// backfillPollInterval is the delay between backfill status polls.")
    lines.append("// Tests can override this to avoid real sleeps.")
    lines.append("var backfillPollInterval = 5 * time.Second")
    lines.append("")
    lines.append("// RegisterAll adds all generated resource commands to the root command.")
    lines.append("func RegisterAll(rootCmd *cobra.Command) {")
    for resource_name in resources:
        camel_name = snake_to_camel(resource_name)
        lines.append(f"\trootCmd.AddCommand({camel_name}Cmd)")
    lines.append("}")
    return "\n".join(lines) + "\n"


def _gen_auth_go():
    """Generate auth.go — domain resolution, auth resolution, profile name resolution."""
    lines = _gen_file_header()
    lines.extend(_gen_all_imports())
    lines.append("// GetDomain returns the API domain. Priority: SUPERMETRICS_DOMAIN env var > buildcfg default.")
    lines.append("func GetDomain() string {")
    lines.append('\tif d := viper.GetString("domain"); d != "" {')
    lines.append("\t\treturn d")
    lines.append("\t}")
    lines.append("\treturn buildcfg.DefaultDomain")
    lines.append("}")
    lines.append("")
    lines.append("// resolveAuth resolves the API domain and authentication token from the command's flags, environment, and config.")
    lines.append("func resolveAuth(cmd *cobra.Command) (string, string, error) {")
    lines.append("\tdomain := GetDomain()")
    lines.append("\toauthCfg, err := auth.LoadOAuthConfig()")
    lines.append("\tif err != nil {")
    lines.append('\t\treturn "", "", err')
    lines.append("\t}")
    lines.append("\tapiKey, err := auth.ResolveToken(")
    lines.append('\t\tcmd.Root().PersistentFlags().Lookup("api-key").Value.String(),')
    lines.append("\t\tos.LookupEnv,")
    lines.append("\t\tdomain,")
    lines.append("\t\toauthCfg,")
    lines.append("\t\tresolveProfileName(cmd),")
    lines.append("\t)")
    lines.append("\tif err != nil {")
    lines.append('\t\treturn "", "", err')
    lines.append("\t}")
    lines.append("\treturn domain, apiKey, nil")
    lines.append("}")
    lines.append("")
    lines.append("// resolveProfileName returns the active profile name.")
    lines.append("// Priority: --profile flag > SUPERMETRICS_PROFILE env > active_profile in config > default.")
    lines.append("func resolveProfileName(cmd *cobra.Command) string {")
    lines.append('\tif p := cmd.Root().PersistentFlags().Lookup("profile").Value.String(); p != "" {')
    lines.append("\t\treturn p")
    lines.append("\t}")
    lines.append('\tif p, ok := os.LookupEnv("SUPERMETRICS_PROFILE"); ok && p != "" {')
    lines.append("\t\treturn p")
    lines.append("\t}")
    lines.append("\tcfg, err := config.Load()")
    lines.append('\tif err == nil && cfg.ActiveProfile != "" {')
    lines.append("\t\treturn cfg.ActiveProfile")
    lines.append("\t}")
    lines.append("\treturn config.DefaultProfile")
    lines.append("}")
    return "\n".join(lines) + "\n"


def _gen_request_go():
    """Generate request.go — resolveTimeout, executeRequest, isTerminal, shouldUseColor, printResult, dryRunRequest."""
    lines = _gen_file_header()
    lines.extend(_gen_all_imports())
    lines.append("// resolveTimeout returns the user-specified --timeout or the per-command default.")
    lines.append("func resolveTimeout(cmd *cobra.Command, defaultTimeout time.Duration) time.Duration {")
    lines.append('\tif f := cmd.Root().PersistentFlags().Lookup("timeout"); f != nil {')
    lines.append('\t\tif t := f.Value.String(); t != "" {')
    lines.append("\t\t\td, err := time.ParseDuration(t)")
    lines.append("\t\t\tif err == nil {")
    lines.append("\t\t\t\treturn d")
    lines.append("\t\t\t}")
    lines.append("\t\t}")
    lines.append("\t}")
    lines.append("\treturn defaultTimeout")
    lines.append("}")
    lines.append("")
    lines.append("// isTerminal reports whether f is a terminal.")
    lines.append("func isTerminal(f *os.File) bool {")
    lines.append("\treturn isatty.IsTerminal(f.Fd()) || isatty.IsCygwinTerminal(f.Fd())")
    lines.append("}")
    lines.append("")
    lines.append("// shouldUseColor returns true if colored output should be used.")
    lines.append("// Honors the --no-color flag and the NO_COLOR env var (https://no-color.org/).")
    lines.append("func shouldUseColor(cmd *cobra.Command) bool {")
    lines.append('\tnoColor, _ := cmd.Root().PersistentFlags().GetBool("no-color")')
    lines.append("\tif noColor {")
    lines.append("\t\treturn false")
    lines.append("\t}")
    lines.append('\tif _, ok := os.LookupEnv("NO_COLOR"); ok {')
    lines.append("\t\treturn false")
    lines.append("\t}")
    lines.append("\treturn isTerminal(os.Stdout)")
    lines.append("}")
    lines.append("")
    lines.append("// executeRequest sends an HTTP request and returns the parsed JSON response.")
    lines.append("func executeRequest(cmd *cobra.Command, method, url string, body io.Reader, apiKey string, timeout time.Duration, spinnerText string) (any, error) {")
    lines.append('\tverbose, _ := cmd.Root().PersistentFlags().GetBool("verbose")')
    lines.append('\tnoRetry, _ := cmd.Root().PersistentFlags().GetBool("no-retry")')
    lines.append('\tquiet, _ := cmd.Root().PersistentFlags().GetBool("quiet")')
    lines.append("")
    lines.extend(_gen_spinner_block(1))
    lines.append("\tresp, err := httpclient.Do(context.Background(), httpclient.Request{")
    lines.append("\t\tMethod:       method,")
    lines.append("\t\tURL:          url,")
    lines.append("\t\tBody:         body,")
    lines.append("\t\tAPIKey:       apiKey,")
    lines.append("\t\tTimeout:      timeout,")
    lines.append("\t\tVerbose:      verbose,")
    lines.append("\t\tClient:       httpClient,")
    lines.append("\t\tDisableRetry: noRetry,")
    lines.append("\t})")
    lines.append("\tif err != nil {")
    lines.append("\t\treturn nil, err")
    lines.append("\t}")
    lines.append("\treturn resp.ParseJSON()")
    lines.append("}")
    lines.append("")
    lines.append("// printResult formats and prints the result to stdout using the command's output flags.")
    lines.append("func printResult(cmd *cobra.Command, result any) error {")
    lines.append('\toutputFormat := cmd.Root().PersistentFlags().Lookup("output").Value.String()')
    lines.append('\tflatten, _ := cmd.Root().PersistentFlags().GetBool("flatten")')
    lines.append('\tfieldsStr := cmd.Root().PersistentFlags().Lookup("fields").Value.String()')
    lines.append("\tvar fields []string")
    lines.append('\tif fieldsStr != "" {')
    lines.append('\t\tfields = strings.Split(fieldsStr, ",")')
    lines.append("\t}")
    lines.append("\treturn output.Print(cmd.OutOrStdout(), result, output.PrintOptions{Format: outputFormat, UseColor: shouldUseColor(cmd), Flatten: flatten, Fields: fields})")
    lines.append("}")
    lines.append("")
    lines.append("// dryRunRequest prints the request details without executing it.")
    lines.append("func dryRunRequest(cmd *cobra.Command, method, url string, body io.Reader) {")
    lines.append("\tw := cmd.ErrOrStderr()")
    lines.append('\tfmt.Fprintf(w, "%s %s\\n", method, url)')
    lines.append("\tif body != nil {")
    lines.append("\t\tdata, err := io.ReadAll(body)")
    lines.append("\t\tif err == nil && len(data) > 0 {")
    lines.append('\t\t\tfmt.Fprintf(w, "Body: %s\\n", string(data))')
    lines.append("\t\t}")
    lines.append("\t}")
    lines.append("}")
    return "\n".join(lines) + "\n"


def _gen_polling_go():
    """Generate polling.go — async query execution, pagination, backfill polling, status helpers."""
    lines = _gen_file_header()
    lines.extend(_gen_all_imports())

    # executeAsyncQueryWithMeta
    lines.append("// executeAsyncQueryWithMeta sends a query with sync_timeout=0, polls until completion,")
    lines.append("// and returns both data and response metadata.")
    lines.append("func executeAsyncQueryWithMeta(cmd *cobra.Command, baseURL, initialURL string, queryParams map[string]any, apiKey string, timeout time.Duration, spinnerText string) (any, map[string]any, error) {")
    lines.append('\tverbose, _ := cmd.Root().PersistentFlags().GetBool("verbose")')
    lines.append('\tnoRetry, _ := cmd.Root().PersistentFlags().GetBool("no-retry")')
    lines.append('\tquiet, _ := cmd.Root().PersistentFlags().GetBool("quiet")')
    lines.append("")
    lines.append("\tctx, cancel := context.WithTimeout(context.Background(), timeout)")
    lines.append("\tdefer cancel()")
    lines.append("")
    lines.extend(_gen_spinner_block(1))
    lines.append("\tresp, err := httpclient.Do(ctx, httpclient.Request{")
    lines.append('\t\tMethod:  "GET",')
    lines.append("\t\tURL:     initialURL,")
    lines.append("\t\tAPIKey:  apiKey,")
    lines.append("\t\tTimeout: timeout,")
    lines.append("\t\tVerbose: verbose,")
    lines.append("\t\tClient:  httpClient,")
    lines.append("\t\tDisableRetry: noRetry,")
    lines.append("\t})")
    lines.append("\tif err != nil {")
    lines.append("\t\treturn nil, nil, err")
    lines.append("\t}")
    lines.append("\tdata, meta, err := resp.ParseJSONWithMeta()")
    lines.append("\tif err != nil {")
    lines.append("\t\treturn nil, nil, err")
    lines.append("\t}")
    lines.append("")
    lines.append('\tstatusCode, _ := meta["status_code"].(string)')
    lines.append("\tif isQueryDone(statusCode) {")
    lines.append('\t\tif statusCode != "SUCCESS" {')
    lines.append('\t\t\treturn nil, meta, fmt.Errorf("query failed with status: %s", statusCode)')
    lines.append("\t\t}")
    lines.append("\t\treturn data, meta, nil")
    lines.append("\t}")
    lines.append("")
    lines.append('\tscheduleID, _ := meta["schedule_id"].(string)')
    lines.append("\tif verbose {")
    lines.append('\t\tfmt.Fprintf(os.Stderr, "Query pending, polling with schedule_id: %s\\n", scheduleID)')
    lines.append("\t}")
    lines.append("")
    lines.append("\tstart := time.Now()")
    lines.append("\tfor {")
    lines.append("\t\tselect {")
    lines.append("\t\tcase <-ctx.Done():")
    lines.append('\t\t\treturn nil, nil, fmt.Errorf("query timed out after %s", timeout)')
    lines.append("\t\tcase <-time.After(pollInterval(time.Since(start))):")
    lines.append('\t\t\tqueryParams["schedule_id"] = scheduleID')
    lines.append('\t\t\tdelete(queryParams, "sync_timeout")')
    lines.append("\t\t\tpollJSON, _ := json.Marshal(queryParams)")
    lines.append('\t\t\tpollURL := baseURL + "?json=" + url.QueryEscape(string(pollJSON))')
    lines.append("\t\t\tif verbose {")
    lines.append('\t\t\t\tfmt.Fprintf(os.Stderr, "Polling: %s\\n", pollURL)')
    lines.append("\t\t\t}")
    lines.append("\t\t\tresp, err = httpclient.Do(ctx, httpclient.Request{")
    lines.append('\t\t\t\tMethod:  "GET",')
    lines.append("\t\t\t\tURL:     pollURL,")
    lines.append("\t\t\t\tAPIKey:  apiKey,")
    lines.append("\t\t\t\tTimeout: timeout,")
    lines.append("\t\t\t\tVerbose: verbose,")
    lines.append("\t\t\t\tClient:  httpClient,")
    lines.append("\t\t\t\tDisableRetry: noRetry,")
    lines.append("\t\t\t})")
    lines.append("\t\t\tif err != nil {")
    lines.append("\t\t\t\treturn nil, nil, err")
    lines.append("\t\t\t}")
    lines.append("\t\t\tdata, meta, err = resp.ParseJSONWithMeta()")
    lines.append("\t\t\tif err != nil {")
    lines.append("\t\t\t\treturn nil, nil, err")
    lines.append("\t\t\t}")
    lines.append('\t\t\tstatusCode, _ = meta["status_code"].(string)')
    lines.append("\t\t\tif isQueryDone(statusCode) {")
    lines.append('\t\t\t\tif statusCode != "SUCCESS" {')
    lines.append('\t\t\t\t\treturn nil, meta, fmt.Errorf("query failed with status: %s", statusCode)')
    lines.append("\t\t\t\t}")
    lines.append("\t\t\t\treturn data, meta, nil")
    lines.append("\t\t\t}")
    lines.append("\t\t}")
    lines.append("\t}")
    lines.append("}")
    lines.append("")

    # executeAsyncQuery wrapper
    lines.append("// executeAsyncQuery sends a query with sync_timeout=0, then polls until completion.")
    lines.append("func executeAsyncQuery(cmd *cobra.Command, baseURL, initialURL string, queryParams map[string]any, apiKey string, timeout time.Duration, spinnerText string) (any, error) {")
    lines.append("\tdata, _, err := executeAsyncQueryWithMeta(cmd, baseURL, initialURL, queryParams, apiKey, timeout, spinnerText)")
    lines.append("\treturn data, err")
    lines.append("}")
    lines.append("")

    # executeAsyncQueryPaginated
    lines.append("// executeAsyncQueryPaginated fetches the first page via async query, then follows")
    lines.append("// pagination links to accumulate all results. Data is array-of-arrays where the")
    lines.append("// first row is headers; subsequent pages' headers are skipped during accumulation.")
    lines.append("func executeAsyncQueryPaginated(cmd *cobra.Command, baseURL, initialURL string, queryParams map[string]any, apiKey string, timeout time.Duration, spinnerText string, fetchAll bool, limit int) (any, error) {")
    lines.append('\tverbose, _ := cmd.Root().PersistentFlags().GetBool("verbose")')
    lines.append('\tnoRetry, _ := cmd.Root().PersistentFlags().GetBool("no-retry")')
    lines.append("")
    lines.append("\tdata, meta, err := executeAsyncQueryWithMeta(cmd, baseURL, initialURL, queryParams, apiKey, timeout, spinnerText)")
    lines.append("\tif err != nil {")
    lines.append("\t\treturn nil, err")
    lines.append("\t}")
    lines.append("")
    lines.append('\tpaginate, _ := meta["paginate"].(map[string]any)')
    lines.append('\tnextURL, _ := paginate["next"].(string)')
    lines.append('\tif nextURL == "" {')
    lines.append("\t\treturn data, nil // No pagination needed")
    lines.append("\t}")
    lines.append("")
    lines.append('\tresultMeta, _ := meta["result"].(map[string]any)')
    lines.append('\ttotalRows := int64(toFloat64(resultMeta["total_rows"]))')
    lines.append("")
    lines.append("\trows, ok := data.([]any)")
    lines.append("\tif !ok || len(rows) < 2 {")
    lines.append("\t\treturn data, nil")
    lines.append("\t}")
    lines.append("\theaders := rows[0]")
    lines.append("\taccumulated := make([]any, len(rows)-1)")
    lines.append("\tcopy(accumulated, rows[1:])")
    lines.append("")
    lines.append("\tif limit > 0 && len(accumulated) >= limit {")
    lines.append("\t\taccumulated = accumulated[:limit]")
    lines.append("\t\tresult := make([]any, 0, 1+len(accumulated))")
    lines.append("\t\tresult = append(result, headers)")
    lines.append("\t\tresult = append(result, accumulated...)")
    lines.append("\t\treturn result, nil")
    lines.append("\t}")
    lines.append("")
    lines.append("\tif verbose {")
    lines.append('\t\tfmt.Fprintf(os.Stderr, "Fetched %d/%d rows\\n", len(accumulated), totalRows)')
    lines.append("\t}")
    lines.append("")
    lines.append("\tctx, cancel := context.WithTimeout(context.Background(), timeout)")
    lines.append("\tdefer cancel()")
    lines.append("")
    lines.append('\tfor nextURL != "" {')
    lines.append("\t\tresp, err := httpclient.Do(ctx, httpclient.Request{")
    lines.append('\t\t\tMethod:       "GET",')
    lines.append("\t\t\tURL:          nextURL,")
    lines.append("\t\t\tAPIKey:       apiKey,")
    lines.append("\t\t\tTimeout:      timeout,")
    lines.append("\t\t\tVerbose:      verbose,")
    lines.append("\t\t\tClient:       httpClient,")
    lines.append("\t\t\tDisableRetry: noRetry,")
    lines.append("\t\t})")
    lines.append("\t\tif err != nil {")
    lines.append("\t\t\treturn nil, err")
    lines.append("\t\t}")
    lines.append("\t\tpageData, pageMeta, err := resp.ParseJSONWithMeta()")
    lines.append("\t\tif err != nil {")
    lines.append("\t\t\treturn nil, err")
    lines.append("\t\t}")
    lines.append("")
    lines.append("\t\tpageRows, ok := pageData.([]any)")
    lines.append("\t\tif !ok || len(pageRows) < 2 {")
    lines.append("\t\t\tbreak")
    lines.append("\t\t}")
    lines.append("\t\tdataRows := pageRows[1:] // Skip header row")
    lines.append("")
    lines.append("\t\tif limit > 0 {")
    lines.append("\t\t\tremaining := limit - len(accumulated)")
    lines.append("\t\t\tif remaining <= 0 {")
    lines.append("\t\t\t\tbreak")
    lines.append("\t\t\t}")
    lines.append("\t\t\tif len(dataRows) > remaining {")
    lines.append("\t\t\t\tdataRows = dataRows[:remaining]")
    lines.append("\t\t\t}")
    lines.append("\t\t}")
    lines.append("")
    lines.append("\t\taccumulated = append(accumulated, dataRows...)")
    lines.append("")
    lines.append("\t\tif verbose {")
    lines.append('\t\t\tfmt.Fprintf(os.Stderr, "Fetched %d/%d rows\\n", len(accumulated), totalRows)')
    lines.append("\t\t}")
    lines.append("")
    lines.append("\t\tif limit > 0 && len(accumulated) >= limit {")
    lines.append("\t\t\tbreak")
    lines.append("\t\t}")
    lines.append("")
    lines.append('\t\tpaginate, _ = pageMeta["paginate"].(map[string]any)')
    lines.append('\t\tnextURL, _ = paginate["next"].(string)')
    lines.append("\t}")
    lines.append("")
    lines.append("\tresult := make([]any, 0, 1+len(accumulated))")
    lines.append("\tresult = append(result, headers)")
    lines.append("\tresult = append(result, accumulated...)")
    lines.append("\treturn result, nil")
    lines.append("}")
    lines.append("")

    # Status helpers
    lines.append("// isQueryDone reports whether a query status code represents a terminal state.")
    lines.append("func isQueryDone(statusCode string) bool {")
    lines.append("\tswitch statusCode {")
    lines.append('\tcase "SUCCESS", "FAILURE", "STOPPED", "PROCESS_EXITED":')
    lines.append("\t\treturn true")
    lines.append("\t}")
    lines.append("\treturn false")
    lines.append("}")
    lines.append("")
    lines.append("// pollInterval returns the polling delay based on elapsed time.")
    lines.append("// Fast at first (1s), then backs off (2s after 5s, 5s after 20s).")
    lines.append("func pollInterval(elapsed time.Duration) time.Duration {")
    lines.append("\tswitch {")
    lines.append("\tcase elapsed < 5*time.Second:")
    lines.append("\t\treturn 1 * time.Second")
    lines.append("\tcase elapsed < 20*time.Second:")
    lines.append("\t\treturn 2 * time.Second")
    lines.append("\tdefault:")
    lines.append("\t\treturn 5 * time.Second")
    lines.append("\t}")
    lines.append("}")
    lines.append("")

    # waitForBackfill
    lines.append("// waitForBackfill polls a backfill endpoint until it reaches a terminal state,")
    lines.append("// showing a progress bar with transfer run counts.")
    lines.append("func waitForBackfill(cmd *cobra.Command, getURL, apiKey string, timeout time.Duration) (any, error) {")
    lines.append('\tverbose, _ := cmd.Root().PersistentFlags().GetBool("verbose")')
    lines.append('\tnoRetry, _ := cmd.Root().PersistentFlags().GetBool("no-retry")')
    lines.append('\tquiet, _ := cmd.Root().PersistentFlags().GetBool("quiet")')
    lines.append("")
    lines.append("\tctx, cancel := context.WithTimeout(context.Background(), timeout)")
    lines.append("\tdefer cancel()")
    lines.append("")
    lines.append("\tshowBar := isTerminal(os.Stderr) && !quiet && !verbose")
    lines.append("\tvar bar *progressbar.ProgressBar")
    lines.append("")
    lines.append("\tfor {")
    lines.append("\t\tselect {")
    lines.append("\t\tcase <-ctx.Done():")
    lines.append('\t\t\treturn nil, fmt.Errorf("backfill timed out after %s", timeout)')
    lines.append("\t\tcase <-time.After(backfillPollInterval):")
    lines.append("\t\t\tresp, err := httpclient.Do(ctx, httpclient.Request{")
    lines.append('\t\t\t\tMethod:       "GET",')
    lines.append("\t\t\t\tURL:          getURL,")
    lines.append("\t\t\t\tAPIKey:       apiKey,")
    lines.append("\t\t\t\tTimeout:      timeout,")
    lines.append("\t\t\t\tVerbose:      verbose,")
    lines.append("\t\t\t\tClient:       httpClient,")
    lines.append("\t\t\t\tDisableRetry: noRetry,")
    lines.append("\t\t\t})")
    lines.append("\t\t\tif err != nil {")
    lines.append("\t\t\t\treturn nil, err")
    lines.append("\t\t\t}")
    lines.append("\t\t\tdata, err := resp.ParseJSON()")
    lines.append("\t\t\tif err != nil {")
    lines.append("\t\t\t\treturn nil, err")
    lines.append("\t\t\t}")
    lines.append("")
    lines.append("\t\t\tm, ok := data.(map[string]any)")
    lines.append("\t\t\tif !ok {")
    lines.append('\t\t\t\treturn nil, fmt.Errorf("unexpected response format")')
    lines.append("\t\t\t}")
    lines.append("")
    lines.append('\t\t\tstatus, _ := m["status"].(string)')
    lines.append('\t\t\ttotal := int(toFloat64(m["transfer_runs_total"]))')
    lines.append('\t\t\tcompleted := int(toFloat64(m["transfer_runs_completed"]))')
    lines.append('\t\t\tfailed := int(toFloat64(m["transfer_runs_failed"]))')
    lines.append("")
    lines.append("\t\t\tif verbose {")
    lines.append('\t\t\t\tfmt.Fprintf(os.Stderr, "Backfill status: %s (%d/%d completed, %d failed)\\n", status, completed, total, failed)')
    lines.append("\t\t\t}")
    lines.append("")
    lines.append("\t\t\tif showBar && total > 0 {")
    lines.append("\t\t\t\tif bar == nil {")
    lines.append("\t\t\t\t\tbar = progressbar.NewOptions(total,")
    lines.append("\t\t\t\t\t\tprogressbar.OptionSetWriter(os.Stderr),")
    lines.append("\t\t\t\t\t\tprogressbar.OptionEnableColorCodes(true),")
    lines.append("\t\t\t\t\t\tprogressbar.OptionShowCount(),")
    lines.append("\t\t\t\t\t\tprogressbar.OptionShowElapsedTimeOnFinish(),")
    lines.append("\t\t\t\t\t\tprogressbar.OptionSetWidth(30),")
    lines.append("\t\t\t\t\t)")
    lines.append("\t\t\t\t}")
    lines.append("\t\t\t\tbar.ChangeMax(total)")
    lines.append("\t\t\t\t_ = bar.Set(completed)")
    lines.append("\t\t\t\tif failed > 0 {")
    lines.append('\t\t\t\t\tbar.Describe(fmt.Sprintf("[cyan]Backfill: %d failed[reset]", failed))')
    lines.append("\t\t\t\t} else {")
    lines.append('\t\t\t\t\tbar.Describe("[cyan]Backfill progress[reset]")')
    lines.append("\t\t\t\t}")
    lines.append("\t\t\t} else if !quiet && !verbose && !showBar && total > 0 {")
    lines.append('\t\t\t\tfmt.Fprintf(os.Stderr, "Backfill: %d/%d runs (%d failed) — %s\\n", completed, total, failed, status)')
    lines.append("\t\t\t}")
    lines.append("")
    lines.append("\t\t\tif isBackfillDone(status) {")
    lines.append("\t\t\t\tif bar != nil {")
    lines.append("\t\t\t\t\t_ = bar.Finish()")
    lines.append("\t\t\t\t}")
    lines.append('\t\t\t\tif status != "COMPLETED" {')
    lines.append('\t\t\t\t\treturn data, fmt.Errorf("backfill %s", strings.ToLower(status))')
    lines.append("\t\t\t\t}")
    lines.append("\t\t\t\treturn data, nil")
    lines.append("\t\t\t}")
    lines.append("\t\t}")
    lines.append("\t}")
    lines.append("}")
    lines.append("")

    lines.append("// isBackfillDone reports whether a backfill status represents a terminal state.")
    lines.append("func isBackfillDone(status string) bool {")
    lines.append("\tswitch status {")
    lines.append('\tcase "COMPLETED", "FAILED", "CANCELLED":')
    lines.append("\t\treturn true")
    lines.append("\t}")
    lines.append("\treturn false")
    lines.append("}")
    lines.append("")

    lines.append("// toFloat64 safely converts a JSON number value to float64.")
    lines.append("func toFloat64(v any) float64 {")
    lines.append("\tif f, ok := v.(float64); ok {")
    lines.append("\t\treturn f")
    lines.append("\t}")
    lines.append("\treturn 0")
    lines.append("}")
    return "\n".join(lines) + "\n"


def _gen_prompt_go():
    """Generate prompt.go — confirmAction, cleanZeroValues."""
    lines = _gen_file_header()
    lines.extend(_gen_all_imports())
    lines.append("// cleanZeroValues removes zero-value entries from a map, used for optional JSON query parameters.")
    lines.append("func cleanZeroValues(params map[string]any) {")
    lines.append("\tfor k, v := range params {")
    lines.append("\t\tswitch val := v.(type) {")
    lines.append("\t\tcase string:")
    lines.append('\t\t\tif val == "" {')
    lines.append("\t\t\t\tdelete(params, k)")
    lines.append("\t\t\t}")
    lines.append("\t\tcase []string:")
    lines.append("\t\t\tif len(val) == 0 {")
    lines.append("\t\t\t\tdelete(params, k)")
    lines.append("\t\t\t}")
    lines.append("\t\tcase int:")
    lines.append("\t\t\tif val == 0 {")
    lines.append("\t\t\t\tdelete(params, k)")
    lines.append("\t\t\t}")
    lines.append("\t\tcase int64:")
    lines.append("\t\t\tif val == 0 {")
    lines.append("\t\t\t\tdelete(params, k)")
    lines.append("\t\t\t}")
    lines.append("\t\tcase float64:")
    lines.append("\t\t\tif val == 0 {")
    lines.append("\t\t\t\tdelete(params, k)")
    lines.append("\t\t\t}")
    lines.append("\t\t}")
    lines.append("\t}")
    lines.append("}")
    lines.append("")
    lines.append("// confirmAction prompts the user for confirmation before a destructive action.")
    lines.append("// Skipped when --yes flag is set or stdin is not a terminal.")
    lines.append("func confirmAction(cmd *cobra.Command, message string) error {")
    lines.append('\tyes, _ := cmd.Flags().GetBool("yes")')
    lines.append("\tif yes {")
    lines.append("\t\treturn nil")
    lines.append("\t}")
    lines.append("\tif !isTerminal(os.Stdin) {")
    lines.append("\t\treturn nil")
    lines.append("\t}")
    lines.append('\tfmt.Fprintf(cmd.ErrOrStderr(), "%s [y/N]: ", message)')
    lines.append("\tanswer, err := bufio.NewReader(os.Stdin).ReadString('\\n')")
    lines.append("\tif err != nil {")
    lines.append('\t\treturn fmt.Errorf("cancelled")')
    lines.append("\t}")
    lines.append("\tanswer = strings.TrimSpace(answer)")
    lines.append('\tif answer != "y" && answer != "Y" {')
    lines.append('\t\treturn fmt.Errorf("cancelled")')
    lines.append("\t}")
    lines.append("\treturn nil")
    lines.append("}")
    return "\n".join(lines) + "\n"


def generate_register_files(resources):
    """Generate helper files split by concern. Returns dict of {filename: content}."""
    return {
        "register.go": _gen_register_go(resources),
        "auth.go": _gen_auth_go(),
        "request.go": _gen_request_go(),
        "polling.go": _gen_polling_go(),
        "prompt.go": _gen_prompt_go(),
    }
